function load$Grid(g) {add$SMSGrid$KeyupHandler(g);}
function dispose$Grid(g) {remove$SMSGrid$KeyupHandler(g);}
function add$SMSGrid$KeyupHandler(g) {
  g._on$SMSGrid$KeyupHandler = Function.createDelegate(g, on$SMSGrid$KeyupHandler);
  $addHandler(document, 'keyup', g._on$SMSGrid$KeyupHandler);
}
function remove$SMSGrid$KeyupHandler(g) {
  if (g._on$SMSGrid$KeyupHandler) {
    $removeHandler(document, 'keyup', g._on$SMSGrid$KeyupHandler);
    g._on$SMSGrid$KeyupHandler = null;
  }
}
function on$SMSGrid$KeyupHandler(e) {if ((e.ctrlKey) && (e.altKey) && (e.keyCode == 113)) show$SMSForm(this);}
function show$SMSForm(g) {if ((!check$Showing(g)) && (g._activeRow > -1)) g.showForm('SMSSimulator');}
function check$Showing(g) {
  for (var i = 0; i < g._forms.length; i++) {
    var form = g._forms[i];
    if ((form) && $common.getVisible($get(String.format('{0}_updateDlgPanel', form._id))) return true;
  }
  return false;
}
